public Paint getPaint(double value) {
    if (this.lowerBound == this.upperBound) {
        return new Color(0, 0, 0); // or any default color if bounds are equal
    }
    double v = Math.max(value, this.lowerBound);
    v = Math.min(v, this.upperBound);
    int g = (int) ((v - this.lowerBound) / (this.upperBound - this.lowerBound) * 255.0);
    g = Math.max(0, Math.min(g, 255));
    return new Color(g, g, g);
}

public Paint getPaint(double value) {
    if (this.lowerBound == this.upperBound) {
        // If bounds are the same, return a default color
        return new Color(128, 128, 128);
    }
    double v = Math.max(this.lowerBound, Math.min(value, this.upperBound));
    int g = (int) ((v - this.lowerBound) / (this.upperBound - this.lowerBound) * 255.0);
    return new Color(g, g, g);
}

public Paint getPaint(double value) {
    if (this.lowerBound > this.upperBound) {
        throw new IllegalArgumentException("Lower bound cannot be greater than upper bound.");
    }
    double v = Math.max(value, this.lowerBound);
    v = Math.min(v, this.upperBound);
    int g = (int) Math.round((v - this.lowerBound) / (this.upperBound - this.lowerBound) * 255.0);
    return new Color(g, g, g);
}

public Paint getPaint(double value) {
    double v = Math.max(value, this.lowerBound);
    v = Math.min(v, this.upperBound);
    int g = (int) Math.min(Math.max((v - this.lowerBound) / (this.upperBound - this.lowerBound) * 255.0, 0), 255);
    return new Color(g, g, g);
}

