protected void checkRequiredOptions()
    throws MissingOptionException
{
    // if there are required options that have not been
    // processed
    List<String> requiredOptions = getRequiredOptions();
    if (!requiredOptions.isEmpty())
    {
        String errorMessage = "Missing required option" + (requiredOptions.size() == 1 ? "" : "s") + ": " + String.join(", ", requiredOptions);
        throw new MissingOptionException(errorMessage);
    }
}

protected void checkRequiredOptions()
    throws MissingOptionException
{
    // if there are required options that have not been
    // processed
    List<String> requiredOptions = getRequiredOptions();
    if (requiredOptions != null && requiredOptions.size() > 0)
    {
        StringBuilder buff = new StringBuilder("Missing required option");
        buff.append(requiredOptions.size() == 1 ? "" : "s");
        buff.append(": ");

        // loop through the required options
        for (int i = 0; i < requiredOptions.size(); i++) {
            String option = requiredOptions.get(i);
            if (option != null) {
                buff.append(option);
                if (i < requiredOptions.size() - 1) {
                    buff.append(", ");
                }
            }
        }

        throw new MissingOptionException(buff.toString());
    }
}

protected void checkRequiredOptions()
    throws MissingOptionException
{
    // Retrieve the list of required options
    List<Object> requiredOptions = getRequiredOptions();

    // Check if the list of required options is null or empty
    if (requiredOptions == null || requiredOptions.size() == 0)
    {
        return; // No required options to check
    }

    // Initialize a StringBuilder for constructing the error message
    StringBuilder buff = new StringBuilder("Missing required option");
    buff.append(requiredOptions.size() == 1 ? "" : "s");
    buff.append(": ");

    // Iterate over the required options and append them to the message
    for (int i = 0; i < requiredOptions.size(); i++)
    {
        buff.append(requiredOptions.get(i));
        if (i < requiredOptions.size() - 1)
        {
            buff.append(", ");
        }
    }

    // Throw the exception with the constructed message
    throw new MissingOptionException(buff.toString());
}

protected void checkRequiredOptions()
    throws MissingOptionException
{
    // Retrieve the list of required options
    List<Object> requiredOptions = getRequiredOptions();

    // Check if there are any required options that have not been processed
    if (requiredOptions != null && !requiredOptions.isEmpty())
    {
        StringBuilder buff = new StringBuilder("Missing required option");
        buff.append(requiredOptions.size() == 1 ? "" : "s");
        buff.append(": ");

        // Loop through the required options and append them to the buffer
        for (int i = 0; i < requiredOptions.size(); i++)
        {
            Object option = requiredOptions.get(i);
            if (option != null)
            {
                buff.append(option.toString());
                if (i < requiredOptions.size() - 1)
                {
                    buff.append(", ");
                }
            }
        }

        throw new MissingOptionException(buff.toString());
    }
}

