private boolean containsExitNode(Node n, int exitType, String labelName) {
  if (matchingExitNode(n, exitType, labelName)) {
    return true;
  }
  for (Node child = n.getFirstChild(); child != null; child = child.getNext()) {
    if (containsExitNode(child, exitType, labelName)) {
