      scope.inferSlotType(node.getString(), type);
      break;

    case Token.GETPROP:
      String qualifiedName = node.getQualifiedName();
      Preconditions.checkNotNull(qualifiedName);

      JSType origType = node.getJSType();
      origType = origType == null ? getNativeType(UNKNOWN_TYPE) : origType;
      scope.inferQualifiedSlot(node, qualifiedName, origType, type);
      break;

    case Token.THIS:
      JSType thisType = scope.getTypeOfThis();
      if (thisType != null) {
        scope.inferQualifiedSlot(node, "this", thisType, type);
      } else {
        throw new IllegalStateException("Type of 'this' could not be determined.");
      }
      break;

    default:
      throw new IllegalArgumentException("Node cannot be refined. \n" +
          node.toStringTree());
  }
}

protected void declareNameInScope(FlowScope scope, Node node, JSType type) {
  switch (node.getType()) {
    case Token.NAME:
      scope.inferSlotType(node.getString(), type);
      break;

    case Token.GETPROP:
      String qualifiedName = node.getQualifiedName();
      Preconditions.checkNotNull(qualifiedName);

      JSType origType = node.getJSType();
      origType = origType == null ? getNativeType(UNKNOWN_TYPE) : origType;
      scope.inferQualifiedSlot(node, qualifiedName, origType, type);
      break;

    case Token.THIS:
      JSType thisType = getNativeType(JSTypeNative.OBJECT_TYPE);
      scope.inferSlotType("this", thisType);
      break;

    default:
      throw new IllegalArgumentException("Node cannot be refined. \n" +
          node.toStringTree());
  }
}

private void checkInterfaceConflictProperties(NodeTraversal t, Node n,
    String functionName, HashMap properties,
    HashMap currentProperties,
    ObjectType interfaceType) {
  ObjectType implicitProto = interfaceType.getImplicitPrototype();
  Set currentPropertyNames;
    // This can be the case if interfaceType is proxy to a non-existent
    // object (which is a bad type annotation, but shouldn't crash).
    currentPropertyNames = implicitProto != null ? implicitProto.getOwnPropertyNames() : new java.util.HashSet();
  for (Iterator iterator = currentPropertyNames.iterator(); iterator.hasNext();) {
    String name = (String) iterator.next();
    ObjectType oType = (ObjectType) properties.get(name);
    if (oType != null) {
      if (!interfaceType.getPropertyType(name).isEquivalentTo(
          oType.getPropertyType(name))) {
        compiler.report(
            t.makeError(n, INCOMPATIBLE_EXTENDED_PROPERTY_TYPE,
                functionName, name, oType.toString(),
                interfaceType.toString()));
      }
    }
    currentProperties.put(name, interfaceType);
  }
  for (Iterator iterator = interfaceType.getCtorExtendedInterfaces().iterator(); iterator.hasNext();) {
    ObjectType iType = (ObjectType) iterator.next();
    checkInterfaceConflictProperties(t, n, functionName, properties,
        currentProperties, iType);
  }
}

