static boolean isSimpleNumber(String s) {
  if (s == null || s.isEmpty()) {
    return false;
  }
  int len = s.length();
  boolean hasLeadingZero = s.charAt(0) == '0';
  for (int index = 0; index < len; index++) {
    char c = s.charAt(index);
    if (c < '0' || c > '9') {
      return false;
    }
  }
  return !hasLeadingZero || s.equals("0");
}

private void replaceAssignmentExpression(Var v, Reference ref,
                                         Map<String, String> varmap) {
  // Compute all of the assignments necessary
  List<Node> nodes = Lists.newArrayList();
  Node val = ref.getAssignedValue();
  if (val == null) {
    return;
  }
  blacklistVarReferencesInTree(val, v.scope);
  Preconditions.checkState(val.getType() == Token.OBJECTLIT);
  Set<String> all = Sets.newLinkedHashSet(varmap.keySet());
  for (Node key = val.getFirstChild(); key != null;
       key = key.getNext()) {
    String var = key.getString();
    Node value = key.removeFirstChild();
    // TODO(user): Copy type information.
    if (var != null && varmap.containsKey(var)) {
      nodes.add(
        new Node(Token.ASSIGN,
                 Node.newString(Token.NAME, varmap.get(var)), value));
      all.remove(var);
    }
  }

  // TODO(user): Better source information.
  for (String var : all) {
    if (varmap.containsKey(var)) {
      nodes.add(
        new Node(Token.ASSIGN,
                 Node.newString(Token.NAME, varmap.get(var)),
                 NodeUtil.newUndefinedNode(null)));
    }
  }

  Node replacement;
  // All assignments evaluate to true, so make sure that the
  // expr statement evaluates to true in case it matters.
  nodes.add(new Node(Token.TRUE));

  // Join these using COMMA.  A COMMA node must have 2 children, so we
  // create a tree. In the tree the first child be the COMMA to match
  // the parser, otherwise tree equality tests fail.
  if (nodes.size() == 1) {
    replacement = nodes.get(0);
  } else {
    replacement = new Node(Token.COMMA);
    Node cur = replacement;
    for (int i = 0; i < nodes.size() - 1; i++) {
      cur.addChildToFront(nodes.get(i));
      Node t = new Node(Token.COMMA);
      cur.addChildToFront(t);
      cur = t;
    }
    cur.addChildToFront(nodes.get(nodes.size() - 1));
  }

  Node replace = ref.getParent();
  if (replace == null) {
    return;
  }
  replacement.copyInformationFromForTree(replace);

  if (replace.getType() == Token.VAR) {
    replace.getParent().replaceChild(
        replace, NodeUtil.newExpr(replacement));
  } else {
    replace.getParent().replaceChild(replace, replacement);
  }
}

private void replaceAssignmentExpression(Var v, Reference ref,
                                     Map<String, String> varmap) {
  // Compute all of the assignments necessary
  List<Node> nodes = Lists.newArrayList();
  Node val = ref.getAssignedValue();
  if (val == null) {
    throw new IllegalArgumentException("Assigned value cannot be null");
  }
  blacklistVarReferencesInTree(val, v.scope);
  Preconditions.checkState(val.getType() == Token.OBJECTLIT);
  Set<String> all = Sets.newLinkedHashSet(varmap.keySet());
  for (Node key = val.getFirstChild(); key != null;
       key = key.getNext()) {
    String var = key.getString();
    Node value = key.removeFirstChild();
    // TODO(user): Copy type information.
    if (varmap.containsKey(var)) {
      nodes.add(
        new Node(Token.ASSIGN,
                 Node.newString(Token.NAME, varmap.get(var)), value));
      all.remove(var);
    }
  }

  // TODO(user): Better source information.
  for (String var : all) {
    if (varmap.containsKey(var)) {
      nodes.add(
        new Node(Token.ASSIGN,
                 Node.newString(Token.NAME, varmap.get(var)),
                 NodeUtil.newUndefinedNode(null)));
    }
  }

  Node replacement;
  // All assignments evaluate to true, so make sure that the
  // expr statement evaluates to true in case it matters.
  nodes.add(new Node(Token.TRUE));

  // Join these using COMMA.  A COMMA node must have 2 children, so we
  // create a tree. In the tree the first child be the COMMA to match
  // the parser, otherwise tree equality tests fail.
  if (nodes.isEmpty()) {
    replacement = NodeUtil.newUndefinedNode(null);
  } else if (nodes.size() == 1) {
    replacement = nodes.get(0);
  } else {
    nodes = Lists.reverse(nodes);
    replacement = new Node(Token.COMMA);
    Node cur = replacement;
    int i;
    for (i = 0; i < nodes.size() - 2; i++) {
      cur.addChildToFront(nodes.get(i));
      Node t = new Node(Token.COMMA);
      cur.addChildToFront(t);
      cur = t;
    }
    cur.addChildToFront(nodes.get(i));
    cur.addChildToFront(nodes.get(i + 1));
  }

  Node replace = ref.getParent();
  if (replace == null) {
    throw new IllegalStateException("Parent node cannot be null");
  }
  replacement.copyInformationFromForTree(replace);

  if (replace.getType() == Token.VAR) {
    replace.getParent().replaceChild(
        replace, NodeUtil.newExpr(replacement));
  } else {
    replace.getParent().replaceChild(replace, replacement);
  }
}

public String getLine(int lineNumber) {
  String js = "";
  try {
    // NOTE(nicksantos): Right now, this is optimized for few warnings.
    // This is probably the right trade-off, but will be slow if there
    // are lots of warnings in one file.
    js = getCode();
  } catch (IOException e) {
    return null;
  }

  int pos = 0;
  int startLine = 1;

  // If we've saved a previous offset and it's for a line less than the
  // one we're searching for, then start at that point.
  if (lineNumber >= lastLine) {
    pos = lastOffset;
    startLine = lastLine;
  }

  for (int n = startLine; n < lineNumber; n++) {
    int nextpos = js.indexOf('\n', pos);
    if (nextpos == -1) {
      return null;
    }
    pos = nextpos + 1;
  }

  // Remember this offset for the next search we do.
  lastOffset = pos;
  lastLine = lineNumber;

  int nextNewLinePos = js.indexOf('\n', pos);
  if (nextNewLinePos == -1) {
    // If next new line cannot be found, check if pos is at the end of the string
    if (pos == js.length()) {
      return null;
    }
    return js.substring(pos);
  } else {
    return js.substring(pos, nextNewLinePos);
  }
}

