private void traverseAndProcessExpression(Node expr, BitSet gen, BitSet kill, boolean conditional) {
  if (expr == null) {
    return;
  }

  switch (expr.getType()) {
    case Token.NAME:
      addToSetIfLocal(expr, gen);
      if (!conditional) {
        addToSetIfLocal(expr, kill);
      }
      break;

    case Token.GETPROP:
      // Process the object part of the getprop expression
      traverseAndProcessExpression(expr.getFirstChild(), gen, kill, conditional);
      break;

    case Token.GETELEM:
      // Process both the object and key parts of the getelem expression
      traverseAndProcessExpression(expr.getFirstChild(), gen, kill, conditional);
      traverseAndProcessExpression(expr.getFirstChild().getNext(), gen, kill, conditional);
      break;

    default:
      // Traverse other types of expressions
      for (Node child = expr.getFirstChild(); child != null; child = child.getNext()) {
        traverseAndProcessExpression(child, gen, kill, conditional);
      }
      break;
  }
}

