static boolean isValidDefineValue(Node val, Set<String> defines) {
  if (val == null) {
    return false;
  }

  switch (val.getType()) {
    case Token.STRING:
    case Token.NUMBER:
    case Token.TRUE:
    case Token.FALSE:
      return true;

    // Binary operators are only valid if both children are valid.
    case Token.BITAND:
    case Token.BITNOT:
    case Token.BITOR:
    case Token.BITXOR:
    case Token.ADD:
    case Token.SUB:
    case Token.MUL:
    case Token.DIV:
    case Token.MOD:
    case Token.LSH:
    case Token.RSH:
    case Token.URSH:
    case Token.AND:
    case Token.OR:
    case Token.COMMA:
      Node left = val.getFirstChild();
      Node right = val.getLastChild();
      return isValidDefineValue(left, defines) && isValidDefineValue(right, defines);

    // Unary operators are valid if the child is valid.
    case Token.NOT:
    case Token.NEG:
      Node child = val.getFirstChild();
      return isValidDefineValue(child, defines);

    // Names are valid if and only if they are defines themselves.
    case Token.NAME:
    case Token.GETPROP:
      if (val.isQualifiedName()) {
        return defines.contains(val.getQualifiedName());
      }
  }
  return false;
}

