void decode(byte[] in, int inPos, int inAvail) {
    if (eof) {
        return;
    }
    if (in == null) {
        throw new IllegalArgumentException("Input byte array cannot be null");
    }
    if (inAvail < 0) {
        eof = true;
    }
    if (buffer == null) {
        resizeBuffer();
    }
    for (int i = 0; i < inAvail; i++) {
        if (buffer.length - pos < decodeSize) {
            resizeBuffer();
        }
        byte b = in[inPos++];
        if (b == PAD) {
            // We're done.
            eof = true;
