public int read(byte b[], int offset, int len) throws IOException {
    if (b == null) {
        throw new NullPointerException();
    } else if (offset < 0 || len < 0) {
        throw new IndexOutOfBoundsException();
    } else if (offset > b.length || offset + len > b.length) {
        throw new IndexOutOfBoundsException();
    } else if (len == 0) {
        return 0;
    } else {
        int maxAttempts = 10; // Limit the number of attempts to prevent infinite loops
        int attempt = 0;
        while (attempt < maxAttempts) {
            if (!base64.hasData()) {
                byte[] buf = new byte[doEncode ? 4096 : 8192];
                int c = in.read(buf);
                // A little optimization to avoid System.arraycopy()
                // when possible.
                if (c > 0 && b.length == len) {
                    base64.setInitialBuffer(b, offset, len);
                }
                if (doEncode) {
                    base64.encode(buf, 0, c);
                } else {
                    base64.decode(buf, 0, c);
                }
            }
            int readLen = base64.readResults(b, offset, len);
            if (readLen != 0) {
                return readLen;
            }
            attempt++;
        }
        // If we reach here, it means readResults() kept returning 0, handle accordingly
        return -1; // Indicating end of stream or no data available
    }
}

