private void writeBits(final DataOutput header, final BitSet bits, final int length) throws IOException {
    if (bits == null || header == null) {
        throw new IllegalArgumentException("Input parameters cannot be null");
    }
    int cache = 0;
    int shift = 7;
    for (int i = 0; i < length; i++) {
        cache |= ((bits.get(i) ? 1 : 0) << shift);
        --shift;
        if (shift == -1) {
            header.write(cache);
            shift = 7;
            cache = 0;
        }
    }
    if (length > 0 && shift != 7) {
        header.write(cache);
    }
}

private void writeBits(final DataOutput header, final BitSet bits, final int length) throws IOException {
    if (bits == null || header == null) {
        throw new IllegalArgumentException("bits and header cannot be null");
    }
    int cache = 0;
    int shift = 7;
    for (int i = 0; i < length; i++) {
        cache |= ((bits.get(i) ? 1 : 0) << shift);
        --shift;
        if (shift < 0) {
            header.write(cache & 0xFF);
            shift = 7;
            cache = 0;
        }
    }
    if (length > 0 && shift != 7) {
        header.write(cache & 0xFF);
    }
}

InputStream decode(final InputStream in, final Coder coder,
        byte[] password) throws IOException {
    if (coder == null || coder.properties == null || coder.properties.length < 5) {
        throw new IllegalArgumentException("Coder or its properties are invalid");
    }
    byte propsByte = coder.properties[0];
    long dictSize = 0;
    for (int i = 0; i < 4; i++) {
        dictSize |= ((long) coder.properties[i + 1] & 0xFF) << (8 * i);
    }
    if (dictSize > LZMAInputStream.DICT_SIZE_MAX) {
        throw new IOException("Dictionary larger than 4GiB maximum size");
    }
    return new LZMAInputStream(in, -1, propsByte, (int) dictSize);
}

