        final byte currentByte = buffer[start];
        if (currentByte < '0' || currentByte > '7'){
            throw new IllegalArgumentException(exceptionMessage(buffer, offset, length, start, currentByte));
        }
        result = (result << 3) + (currentByte - '0'); // convert from ASCII
    }

    return result;
}

private void applyPaxHeadersToCurrentEntry(Map<String, String> headers) {
    /*
     * The following headers are defined for Pax.
     * atime, ctime, charset: cannot use these without changing TarArchiveEntry fields
     * mtime
     * comment
     * gid, gname
     * linkpath
     * size
     * uid,uname
     * SCHILY.devminor, SCHILY.devmajor: don't have setters/getters for those
     */
    for (Entry<String, String> ent : headers.entrySet()){
        String key = ent.getKey();
        String val = ent.getValue();
        try {
            if ("path".equals(key)) {
                currEntry.setName(val);
            } else if ("linkpath".equals(key)) {
                currEntry.setLinkName(val);
            } else if ("gid".equals(key)) {
                currEntry.setGroupId(parseLong(val));
            } else if ("gname".equals(key)) {
                currEntry.setGroupName(val);
            } else if ("uid".equals(key)) {
                currEntry.setUserId(parseInt(val));
            } else if ("uname".equals(key)) {
                currEntry.setUserName(val);
            } else if ("size".equals(key)) {
                currEntry.setSize(parseLong(val));
            } else if ("mtime".equals(key)) {
                currEntry.setModTime((long) (parseDouble(val) * 1000));
            } else if ("SCHILY.devminor".equals(key)) {
                currEntry.setDevMinor(parseInt(val));
            } else if ("SCHILY.devmajor".equals(key)) {
                currEntry.setDevMajor(parseInt(val));
            }
        } catch (NumberFormatException e) {
            // Log or handle the exception as appropriate
            System.err.println("Invalid number format for key: " + key + ", value: " + val);
        } catch (NullPointerException e) {
            // Log or handle the exception as appropriate
            System.err.println("Null value for key: " + key);
        }
    }
}

private int parseInt(String val) throws NumberFormatException {
    long parsedValue = parseLong(val);
    if (parsedValue < Integer.MIN_VALUE || parsedValue > Integer.MAX_VALUE) {
        throw new NumberFormatException("Value out of range for int: " + val);
    }
    return (int) parsedValue;
}

private long parseLong(String val) throws NumberFormatException {
    if (val == null) {
        throw new NumberFormatException("Null value provided");
    }
    return Long.parseLong(val);
}

private double parseDouble(String val) throws NumberFormatException {
    if (val == null) {
        throw new NumberFormatException("Null value provided");
    }
    return Double.parseDouble(val);
}

public static boolean verifyCheckSum(byte[] header) {
    long storedSum = 0;
    long unsignedSum = 0;
    long signedSum = 0;

    for (int i = 0; i < header.length; i++) {
        byte b = header[i];
        if (CHKSUM_OFFSET <= i && i < CHKSUM_OFFSET + CHKSUMLEN) {
            if ('0' <= b && b <= '7') {
                storedSum = storedSum * 8 + (b - '0');
            }
            b = ' ';
        }
        unsignedSum += 0xff & b;
        signedSum += b;
    }
    return storedSum == unsignedSum || storedSum == signedSum;
}

patches.original_code:
/**
* Wikipedia <a href="http://en.wikipedia.org/wiki/Tar_(file_format)#File_header">says</a>:
* <blockquote>
* The checksum is calculated by taking the sum of the unsigned byte values
* of the header block with the eight checksum bytes taken to be ascii
* spaces (decimal value 32). It is stored as a six digit octal number with
* leading zeroes followed by a NUL and then a space. Various
* implementations do not adhere to this format. For better compatibility,
* ignore leading and trailing whitespace, and get the first six digits. In
* addition, some historic tar implementations treated bytes as signed.
* Implementations typically calculate the checksum both ways, and treat it
* as good if either the signed or unsigned sum matches the included
* checksum.
* </blockquote>
* <p>
* The return value of this method should be treated as a best-effort
* heuristic rather than an absolute and final truth. The checksum
* verification logic may well evolve over time as more special cases
* are encountered.
*
* @param header tar header
* @return whether the checksum is reasonably good
* @see <a href="https://issues.apache.org/jira/browse/COMPRESS-191">COMPRESS-191</a>
* @since 1.5
*/
public static boolean verifyCheckSum(byte[] header) {
    long storedSum = 0;
    long unsignedSum = 0;
    long signedSum = 0;

    int digits = 0;
    for (int i = 0; i < header.length; i++) {
        byte b = header[i];
        if (CHKSUM_OFFSET  <= i && i < CHKSUM_OFFSET + CHKSUMLEN) {
            if ('0' <= b && b <= '7' && digits++ < 6) {
                storedSum = storedSum * 8 + b - '0';
            } else if (digits > 0) {
                digits = 6;
            }
            b = ' ';
        }
        unsignedSum += 0xff & b;
        signedSum += b;
    }
    return storedSum == unsignedSum || storedSum == signedSum;
}

