public static int formatLongOctalOrBinaryBytes(final long value, final byte[] buf, final int offset, final int length) {

    // Check whether we are dealing with UID/GID or SIZE field
    final long maxAsOctalChar = length == TarConstants.UIDLEN ? TarConstants.MAXID : TarConstants.MAXSIZE;

    final boolean negative = value < 0;
    if (!negative && value <= maxAsOctalChar) { // OK to store as octal chars
        return formatLongOctalBytes(value, buf, offset, length);
    }

    if (length < 9) {
        formatLongBinary(value, buf, offset, length, negative);
    } else if (length == 9) {
        formatBigIntegerBinary(value, buf, offset, length, negative);
    }

    buf[offset] = (byte) (negative ? 0xff : 0x80);
    return offset + length;
}

public int read(byte[] buffer, int start, int length) throws IOException {
    if (closed) {
        throw new IOException("The stream is closed");
    }
    if (inf.finished() || current == null) {
        return -1;
    }

    // avoid int overflow, check null buffer
    if (buffer == null || start < 0 || length < 0 || start + length > buffer.length) {
        throw new ArrayIndexOutOfBoundsException();
    }

    if (current.getMethod() == ZipArchiveOutputStream.STORED) {
        int csize = (int) current.getSize();
        if (readBytesOfEntry >= csize) {
            return -1;
        }
        if (offsetInBuffer >= lengthOfLastRead) {
            offsetInBuffer = 0;
            if ((lengthOfLastRead = in.read(buf)) == -1) {
                throw new IOException("Truncated ZIP file");
            }
            count(lengthOfLastRead);
            bytesReadFromStream += lengthOfLastRead;
        }
        int toRead = Math.min(length, lengthOfLastRead - offsetInBuffer);
        toRead = Math.min(toRead, csize - readBytesOfEntry);
        System.arraycopy(buf, offsetInBuffer, buffer, start, toRead);
        offsetInBuffer += toRead;
        readBytesOfEntry += toRead;
        crc.update(buffer, start, toRead);
        return toRead;
    }
    if (inf.needsInput()) {
        fill();
        if (lengthOfLastRead == -1) {
            throw new IOException("Truncated ZIP file");
        }
        bytesReadFromStream += lengthOfLastRead;
    }
    int read = 0;
    try {
        read = inf.inflate(buffer, start, length);
    } catch (DataFormatException e) {
        throw new ZipException("Corrupted ZIP file: " + e.getMessage());
    }
    if (read == 0 && inf.finished()) {
        return -1;
    }
    if (read == 0) {
        throw new IOException("Unexpected end of data in ZIP file");
    }
    crc.update(buffer, start, read);
    return read;
}

public static String parseName(byte[] buffer, final int offset, final int length) {
    if (buffer == null) {
        throw new IllegalArgumentException("Buffer cannot be null");
    }
    if (offset < 0 || length < 0 || offset + length > buffer.length) {
        throw new IndexOutOfBoundsException("Offset and length must be within buffer bounds");
    }

    StringBuilder result = new StringBuilder(length);
    int end = offset + length;

    for (int i = offset; i < end; ++i) {
        if (buffer[i] == 0) {
            break;
        }
        result.append((char) (buffer[i] & 0xFF));
    }

    return result.toString();
}

public static long parseOctal(final byte[] buffer, final int offset, final int length) {
    long    result = 0;
    boolean stillPadding = true;
    int     end = offset + length;
    int     start = offset;

    if (length < 2) {
        throw new IllegalArgumentException("Length must be at least 2 bytes");
    }

    for (int i = start; i < end; i++){
        final byte currentByte = buffer[i];
        if (currentByte == 0) {
            if (i != end - 1 && i != end - 2) {
                throw new IllegalArgumentException(exceptionMessage(buffer, offset, length, start, currentByte));
            }
            break;
        }

        // Skip leading spaces
        if (currentByte == (byte) ' ' && stillPadding) {
            continue;
        }

        stillPadding = false;

        // Check for trailing space or NUL
        if (i == end - 1 && currentByte != 0 && currentByte != (byte) ' ') {
            throw new IllegalArgumentException(exceptionMessage(buffer, offset, length, start, currentByte));
        }

        // CheckStyle:MagicNumber OFF
        if (currentByte < '0' || currentByte > '7'){
            throw new IllegalArgumentException(exceptionMessage(buffer, offset, length, start, currentByte));
        }
        result = (result << 3) + (currentByte - '0'); // convert from ASCII
        // CheckStyle:MagicNumber ON
    }

    return result;
}

public int read() throws IOException {
    int current = super.read();
    if (current == '\n') {
        if (lastChar != '\r') {
            lineCounter++;
        }
    } else if (current == '\r') {
        lineCounter++;
    }
    lastChar = current;
    return lastChar;
}

