public String chompBalanced(char open, char close) {
    int start = -1;
    int end = -1;
    int depth = 0;
    char last = 0;
    boolean inQuote = false;
    final char ESC = '\\';

    do {
        if (isEmpty()) break;
        Character c = consume();
        if (last != ESC && (c == '"' || c == '\'' || c == '`'))
            inQuote = !inQuote;
        if (last == 0 || last != ESC) {
            if (c == open && !inQuote) {
                depth++;
                if (start == -1)
                    start = pos;
            }
            else if (c == close && !inQuote)
                depth--;
        }

        if (depth > 0 && last != 0)
            end = pos; // don't include the outer match pair in the return
        last = c;
    } while (depth > 0);
    return (end >= 0) ? queue.substring(start, end) : "";
}

