private void popStackToClose(Token.EndTag endTag) {
    if (endTag == null || endTag.name() == null)
        return; // skip if endTag or its name is null

    String elName = endTag.name().toLowerCase();
    Element firstFound = null;

    for (int pos = stack.size() - 1; pos >= 0; pos--) {
        Element next = stack.get(pos);
        if (next != null && next.nodeName().toLowerCase().equals(elName)) {
            firstFound = next;
            break;
        }
    }
    if (firstFound == null)
        return; // not found, skip

    for (int pos = stack.size() - 1; pos >= 0; pos--) {
        Element next = stack.get(pos);
        if (next == firstFound) {
            stack.remove(pos);
            break;
        }
    }
}

