private static int greatestCommonDivisor(int u, int v) {
    // Handle cases where u or v is zero
    if (u == 0) {
        return Math.abs(v);
    }
    if (v == 0) {
        return Math.abs(u);
    }
    // Handle cases where u or v is Integer.MIN_VALUE
    if (u == Integer.MIN_VALUE && v == Integer.MIN_VALUE) {
        return Integer.MIN_VALUE;
    }
    if (u == Integer.MIN_VALUE) {
        return (v % 2 == 0) ? Math.abs(v) : v;
    }
    if (v == Integer.MIN_VALUE) {
        return (u % 2 == 0) ? Math.abs(u) : u;
    }
    // Make u and v positive to simplify calculations
    u = Math.abs(u);
    v = Math.abs(v);
    // Find power of 2
    int k = 0;
    while ((u & 1) == 0 && (v & 1) == 0 && k < 31) {
        u >>= 1;
        v >>= 1;
        k++;
    }
    if (k == 31) {
        throw new ArithmeticException("overflow: gcd is 2^31");
    }
    // Initialize: u and v have been divided by 2^k and at least one is odd
    while (u != 0) {
        while ((u & 1) == 0) {
            u >>= 1;
        }
        while ((v & 1) == 0) {
            v >>= 1;
        }
        if (u >= v) {
            u -= v;
        } else {
            v -= u;
        }
    }
    return v << k;
}

