public static <T> T[] addAll(T[] array1, T... array2) {
    if (array1 == null) {
        return clone(array2);
    } else if (array2 == null) {
        return clone(array1);
    }
    final Class<?> type1 = array1.getClass().getComponentType();
    final Class<?> type2 = array2.getClass().getComponentType();
    T[] joinedArray = (T[]) Array.newInstance(findCommonSuperclass(type1, type2), array1.length + array2.length);
    System.arraycopy(array1, 0, joinedArray, 0, array1.length);
    System.arraycopy(array2, 0, joinedArray, array1.length, array2.length);
    return joinedArray;
}

private static Class<?> findCommonSuperclass(Class<?> type1, Class<?> type2) {
    if (type1.isAssignableFrom(type2)) {
        return type1;
    } else if (type2.isAssignableFrom(type1)) {
        return type2;
    } else {
        throw new IllegalArgumentException("Incompatible types: " + type1 + " and " + type2);
    }
}

