public double getNumericalMean() {
    int populationSize = getPopulationSize();
    int numberOfSuccesses = getNumberOfSuccesses();
    int sampleSize = getSampleSize();

    if (populationSize <= 0 || sampleSize <= 0) {
        return 0.0;
    }
    if (numberOfSuccesses <= 0) {
        return 0.0;
    }
    if (sampleSize >= populationSize) {
        return (double) numberOfSuccesses;
    }

    int successes = 0;
    for (int i = 0; i < sampleSize; i++) {
        if (Math.random() < (double) (numberOfSuccesses) / populationSize) {
            successes++;
        }
        populationSize--;
        numberOfSuccesses--;
    }
    return (double) successes / sampleSize;
}

public double getNumericalMean() {
    return (double) getSampleSize() * getNumberOfSuccesses() / getPopulationSize();
}

