public boolean equals(Object other) {
    boolean ret;

    if (this == other) { 
        ret = true;
    } else if (other == null) {
        ret = false;
    } else  {
        try {
            Complex rhs = (Complex)other;
            if (rhs.isNaN() || this.isNaN()) {
                ret = rhs.isNaN() && this.isNaN();
            } else {
                final double tol = 1e-9; // General configurable tolerance
                ret = (Math.abs(this.real - rhs.getReal()) < tol) && (Math.abs(this.imaginary - rhs.getImaginary()) < tol);
            }
        } catch (ClassCastException ex) {
            // ignore exception
            ret = false;
        }
    }

    return ret;
}

