public Object answer(InvocationOnMock invocation) {
    if (methodsGuru.isToString(invocation.getMethod())) {
        Object mock = invocation.getMock();
        MockName name = mockUtil.getMockName(mock);
        if (name.isDefault()) {
            return "Mock for " + mockUtil.getMockSettings(mock).getTypeToMock().getSimpleName() + ", hashCode: " + mock.hashCode();
        } else {
            return name.toString();
        }
    } else if (methodsGuru.isCompareToMethod(invocation.getMethod())) {
        // see issue 184.
        // mocks by default should return 0 if references are the same, otherwise some other value because they are not the same.
        // Only for compareTo() method by the Comparable interface
        Object arg = invocation.getArguments()[0];
        Object mock = invocation.getMock();
        if (arg == mock) {
            return 0;
        } else if (arg == null) {
            return -1; // Consistent behavior when comparing to null
        } else {
            // Generate a consistent but arbitrary non-zero value based on hash codes
            return Integer.compare(mock.hashCode(), arg.hashCode());
        }
    }

    Class<?> returnType = invocation.getMethod().getReturnType();
    return returnValueFor(returnType);
}

public Object answer(InvocationOnMock invocation) {
    if (methodsGuru.isToString(invocation.getMethod())) {
        Object mock = invocation.getMock();
        MockName name = mockUtil.getMockName(mock);
        if (name.isDefault()) {
            return "Mock for " + mockUtil.getMockSettings(mock).getTypeToMock().getSimpleName() + ", hashCode: " + mock.hashCode();
        } else {
            return name.toString();
        }
    } else if (methodsGuru.isCompareToMethod(invocation.getMethod())) {
        Object mock = invocation.getMock();
        Object[] args = invocation.getArguments();
        if (args.length > 0 && args[0] != null && args[0].getClass().equals(mock.getClass())) {
            return mock == args[0] ? 0 : 1;
        } else {
            return 1; // If the argument is null or of a different type, return 1
        }
    }

    Class<?> returnType = invocation.getMethod().getReturnType();
    return returnValueFor(returnType);
}

private void injectMockCandidate(Class<?> awaitingInjectionClazz, Set<Object> mocks, Object fieldInstance) {
    for(Field field : orderedInstanceFieldsFrom(awaitingInjectionClazz)) {
        Object selectedMock = mockCandidateFilter.filterCandidate(mocks, field, fieldInstance);
        if (selectedMock != null) {
            try {
                field.setAccessible(true);
                field.set(fieldInstance, selectedMock);
            } catch (IllegalAccessException e) {
                // Log the exception instead of throwing a RuntimeException
                System.err.println("Failed to inject mock into field: " + field.getName() + " in class: " + field.getDeclaringClass().getName());
                e.printStackTrace();
            }
        }
    }
}

