private String formatMethodCall() {
    StringBuilder params = new StringBuilder();
    for (Object arg : invocation.getArguments()) {
        if (params.length() > 0) params.append(", ");
        if (arg == null) {
            params.append("null");
        } else {
            params.append(arg.toString());
        }
    }
    return invocation.getMethod().getName() + "(" + params.toString() + ")";
}

private String formatMethodCall() {
    StringBuilder args = new StringBuilder();
    for (Object arg : invocation.getArguments()) {
        if (args.length() > 0) args.append(", ");
        if (arg == null) {
            args.append("null");
        } else {
            args.append(arg.toString());
        }
    }
    return invocation.getMethod().getName() + "(" + args.toString() + ")";
}

private String formatMethodCall() {
    StringBuilder sb = new StringBuilder(invocation.getMethod().getName());
    sb.append("(");
    Object[] args = invocation.getArguments();
    for (int i = 0; i < args.length; i++) {
        if (i > 0) sb.append(", ");
        if (args[i] == null) {
            sb.append("null");
        } else {
            try {
                sb.append(args[i].toString());
            } catch (Exception e) {
                sb.append("[toString() failed]");
            }
        }
    }
    sb.append(")");
    return sb.toString();
}

private String formatMethodCall() {
    StringBuilder sb = new StringBuilder(invocation.getMethod().getName()).append("(");
    Object[] args = invocation.getArguments();
    for (int i = 0; i < args.length; i++) {
        if (args[i] == null) {
            sb.append("null");
        } else {
            sb.append(String.format("%s", args[i].toString().replace("\"", "\\\"").replace(",", "\\,")));
        }
        if (i < args.length - 1) {
            sb.append(", ");
        }
    }
    sb.append(")");
    return sb.toString();
}

