public void printWrapped(PrintWriter pw, int width, int nextLineTabStop, String text)
    {
        if (pw == null || text == null) {
            throw new IllegalArgumentException("PrintWriter and text cannot be null");
        }

        if (width <= 0 || nextLineTabStop < 0) {
            throw new IllegalArgumentException("Width must be positive and nextLineTabStop must be non-negative");
        }

        if (text.isEmpty()) {
            pw.println();
            return;
        }

        StringBuffer sb = new StringBuffer();
        String[] lines = text.split("\r?\n");
        for (int i = 0; i < lines.length; i++) {
            renderWrappedText(sb, width, nextLineTabStop, lines[i]);
            if (i < lines.length - 1) {
                sb.append('\n');
            }
        }
        pw.println(sb.toString());
    }

