                if (new MockUtil().isMock(instance)) { 
                    // instance has been spied earlier
                    Mockito.reset(instance);
                } else {
                    field.set(testClass, createSpyWithFieldName(instance, field.getName()));
                }
            } catch (IllegalAccessException e) {
                throw new MockitoException("Problems initiating spied field " + field.getName(), e);
            } finally {
                field.setAccessible(wasAccessible);
            }
        }
    }
}

private Object createSpyWithFieldName(Object instance, String fieldName) {
    return Mockito.mock(instance.getClass(), Mockito.withSettings().spiedInstance(instance).name(fieldName));
}

public static String sanitize(String s) {
    if (s == null) {
        return "";
    }
    final char[] chars = s.toCharArray();
    final int len = chars.length;
    final StringBuilder sb = new StringBuilder();
    int maxLength = 255;
    for (int i = 0; i < len && sb.length() < maxLength; i++) {
        final char c = chars[i];
        if (!Character.isISOControl(c)) {
            Character.UnicodeBlock block = Character.UnicodeBlock.of(c);
            if (block != null && block != Character.UnicodeBlock.SPECIALS) {
                sb.append(c);
                continue;
            }
        }
        sb.append('?');
    }
    if (sb.length() >= maxLength) {
        sb.setLength(maxLength - 3);
        sb.append("...");
    }
    return sb.toString();
}

